VALUES
  ('aboriginal-57f41407-moex-00382', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列何者非民法規定所允許自力救濟之方式？', '["無因管理", "正當防衛", "自助行為", "緊急避難"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00383', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲向乙購買二手車一輛，乙尚未交付前，該車即滅失。依民法規定，下列敘述何者錯誤？', '["若該車滅失不可歸責於乙，則免除給付該車之義務", "甲未取得購買之汽車，自無須支付價金", "若該車滅失可歸責於乙，甲得解除買賣契約", "若該車滅失可歸責於乙，甲得向乙請求損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00384', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲經公證將A車贈與乙，在甲將該車所有權移轉於乙之前，因自己之抽象輕過失導致該車滅失。下列敘述 何者正確？', '["縱使為經公證之贈與，贈與人在移轉標的物所有權前，仍得隨時任意撤銷贈與，故乙不得向甲為任何請求", "贈與經公證後，因可歸責於贈與人之事由而致給付不能者，受贈人即得依一般債務不履行規定請求損害 賠償。因甲有抽象輕過失之可歸責事由，故乙得向甲請求債務不履行之損害賠償", "贈與經公證後，因可歸責於贈與人之事由而致給付不能者，受贈人僅得請求賠償贈與物之價額，而贈與 人可否歸責以贈與人是否有抽象輕過失來判斷。因甲有抽象輕過失之可歸責事由，故乙得向甲請求A車 價額之賠償", "贈與經公證後，因可歸責於贈與人之事由而致給付不能者，受贈人僅得請求賠償贈與物之價額，而贈與 人可否歸責以贈與人是否有故意或重大過失來判斷。因甲僅有抽象輕過失，而不具可歸責事由，故乙不 得向甲請求A車價額之賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00385', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲將其機車賣與乙，則乙應符合下列何要件，始取得機車之所有權？①讓與合意 ②交付 ③過戶登記', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00386', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲男喪偶，有一子丙；乙女離婚，有一子丁。若甲乙結婚，雙方於婚後生下一女戊。下列敘述何者正確？', '["甲與丁為直系血親一親等", "乙與丙為直系姻親二親等", "丙與丁為旁系姻親二親等", "丁與戊為旁系血親二親等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00387', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '某甲有弟弟乙，成年兒子丙，爸爸丁，爺爺戊。如不考慮其他因素，依民法規定，某甲應先扶養誰？', '["乙", "丙", "丁", "戊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00388', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲向乙銀行借款新臺幣（下同）1,000萬元。甲喪妻後，於其獨子丙結婚時贈與現金200萬元。半年後， 甲因故去世。甲死亡時，留有現金600萬元。下列敘述何者錯誤？', '["丙得拋棄繼承，避免200萬元視為其所得遺產", "乙得於除斥期間內，以訴撤銷甲對丙之贈與行為", "乙得主張丙之所得遺產為800萬元", "丙得抗辯超出600萬元部分，拒絕以自己財產清償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00389', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列關於貪污治罪條例第12條之寬減規定，下列敘述何者正確？', '["法院審酌其犯罪情節輕微者，即應依此規定減輕其刑", "犯罪所得新臺幣5萬元以下者，即應依此規定減輕其刑", "法院審酌其犯罪情節輕微，且犯罪所得新臺幣5萬元以下者，即應依此規定減輕其刑", "法院審酌其犯罪情節輕微，且犯罪後已繳交全部犯罪所得者，即應依此規定減輕其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00390', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '關於辯護人接見羈押之被告，下列敘述何者正確？', '["非有事證足認有滅證、串證之情形，不得限制", "限制辯護人接見羈押之被告，法官得以言詞為之", "偵查中檢察官認為有限制辯護人接見羈押被告之必要時，得以命令限制之", "檢察官限制辯護人接見羈押之被告時，被告得向檢察總長提起準抗告，以資救濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00391', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '依刑事訴訟法規定，國家機關進行下列程序時，無須對被告履行告知義務？', '["拘提時", "逮捕時", "訊問被告時", "搜索時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
